  1	import * as React from 'react';
  2	import classnames from 'classnames';
  3	import * as _ from 'lodash';
  4	import { useTranslation } from 'react-i18next';
  5	import { Link } from 'react-router-dom-v5-compat';
  6	import { Tooltip } from '@patternfly/react-core';
  7	import {
  8	  observer,
  9	  Node,
 10	  NodeModel,
 11	  useHover,
 12	  createSvgIdUrl,
 13	} from '@patternfly/react-topology';
 14	import {
 15	  ApprovalStatus,
 16	  ApprovalTaskKind,
 17	  CustomRunKind,
 18	  K8sResourceKind,
 19	  TaskKind,
 20	} from '../../types';
 21	import { ApprovalTaskModel, CustomRunModelV1Beta1 } from '../../models';
 22	import {
 23	  getApprovalStatus,
 24	  getApprovalStatusInfo,
 25	} from '../utils/pipeline-approval-utils';
 26	import { truncateMiddle } from './truncate-middle';
 27	import SvgDropShadowFilter from './SvgDropShadowFilter';
 28	import {
 29	  WatchK8sResults,
 30	  getGroupVersionKindForModel,
 31	  useK8sWatchResources,
 32	} from '@openshift-console/dynamic-plugin-sdk';
 33	import { ApprovalStatusIcon } from './StatusIcons';
 34	import { TaskNodeModelData } from './types';
 35	
 36	import './CustomTaskNode.scss';
 37	
 38	type ApprovalTaskNodeProps = {
 39	  element: Node<NodeModel, TaskNodeModelData>;
 40	  disableTooltip?: boolean;
 41	};
 42	
 43	// eslint-disable-next-line @typescript-eslint/naming-convention
 44	export type WatchResource = {
 45	  [key: string]: ApprovalTaskKind & CustomRunKind;
 46	};
 47	
 48	interface ApprovalTaskComponentProps {
 49	  pipelineRunName?: string;
 50	  name: string;
 51	  loaded?: boolean;
 52	  task?: {
 53	    data: TaskKind;
 54	  };
 55	  status: ApprovalStatus;
 56	  namespace: string;
 57	  disableVisualizationTooltip?: boolean;
 58	  width: number;
 59	  height: number;
 60	  customTask?: K8sResourceKind;
 61	}
 62	
 63	const FILTER_ID = 'SvgTaskDropShadowFilterId';
 64	
 65	const ApprovalTaskComponent: React.FC<ApprovalTaskComponentProps> = ({
 66	  pipelineRunName,
 67	  namespace,
 68	  task,
 69	  status,
 70	  name,
 71	  disableVisualizationTooltip,
 72	  width,
 73	  height,
 74	  customTask,
 75	}) => {
 76	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 77	  const showStatusState = !!pipelineRunName;
 78	  const visualName = name || _.get(task, ['metadata', 'name'], '');
 79	  const nameRef = React.useRef();
 80	  const pillRef = React.useRef();
 81	
 82	  const path = customTask?.metadata?.name
 83	    ? `/dev-pipelines/ns/${namespace}/approvals?name=${customTask?.metadata?.name}`
 84	    : undefined;
 85	
 86	  const enableLogLink = status !== ApprovalStatus.Idle && !!path;
 87	  const taskStatusColor = status
 88	    ? getApprovalStatusInfo(status).pftoken.value
 89	    : getApprovalStatusInfo(ApprovalStatus.Idle).pftoken.value;
 90	
 91	  const [hover, hoverRef] = useHover();
 92	  const truncatedVisualName = React.useMemo(
 93	    () =>
 94	      truncateMiddle(visualName, {
 95	        length: showStatusState ? 11 : 14,
 96	        truncateEnd: true,
 97	      }),
 98	    [visualName, showStatusState],
 99	  );
100	
101	  const renderVisualName = (
102	    <text
103	      ref={nameRef}
104	      x={showStatusState ? 30 : width / 2}
105	      y={height / 2 + 1}
106	      className={classnames('odc-pipeline-vis-task-text', {
107	        'is-text-center': !pipelineRunName,
108	        'is-linked': enableLogLink,
109	      })}
110	    >
111	      {truncatedVisualName}
112	    </text>
113	  );
114	
115	  let taskPill = (
116	    <g ref={hoverRef}>
117	      <SvgDropShadowFilter dy={1} id={FILTER_ID} />
118	      <rect
119	        filter={hover ? createSvgIdUrl(FILTER_ID) : ''}
120	        width={width}
121	        height={height}
122	        rx={5}
123	        className={classnames('odc-pipeline-vis-task', {
124	          'is-selected': !!pipelineRunName && hover,
125	          'is-linked': !!pipelineRunName && enableLogLink,
126	        })}
127	        style={{
128	          stroke: pipelineRunName
129	            ? status
130	              ? getApprovalStatusInfo(status).pftoken.value
131	              : getApprovalStatusInfo(ApprovalStatus.Idle).pftoken.value
132	            : '',
133	        }}
134	      />
135	      {visualName !== truncatedVisualName && disableVisualizationTooltip ? (
136	        <Tooltip triggerRef={nameRef} content={visualName}>
137	          {renderVisualName}
138	        </Tooltip>
139	      ) : (
140	        renderVisualName
141	      )}
142	
143	      {showStatusState && (
144	        <svg
145	          width={30}
146	          height={30}
147	          viewBox="-10 -7 30 30"
148	          style={{
149	            color: taskStatusColor,
150	          }}
151	        >
152	          <ApprovalStatusIcon status={status} />
153	        </svg>
154	      )}
155	    </g>
156	  );
157	
158	  if (!disableVisualizationTooltip) {
159	    taskPill = (
160	      <Tooltip
161	        triggerRef={pillRef}
162	        position="bottom"
163	        enableFlip={false}
164	        content={t('Approval Task')}
165	      >
166	        <g ref={pillRef}>{taskPill}</g>
167	      </Tooltip>
168	    );
169	  }
170	  return (
171	    <g
172	      className={classnames('odc-pipeline-topology__task-node', {
173	        'is-link': enableLogLink,
174	      })}
175	    >
176	      {enableLogLink ? <Link to={path}>{taskPill}</Link> : taskPill}
177	    </g>
178	  );
179	};
180	
181	const ApprovalTaskNode: React.FC<ApprovalTaskNodeProps> = ({
182	  element,
183	  disableTooltip,
184	}) => {
185	  const { height, width } = element.getBounds();
186	
187	  const { pipeline, pipelineRun, task } = element.getData();
188	
189	  const customTaskName = `${pipelineRun?.metadata?.name}-${task?.name}`;
190	
191	  const watchedResources = {
192	    customRun: {
193	      groupVersionKind: getGroupVersionKindForModel(CustomRunModelV1Beta1),
194	      name: customTaskName,
195	      namespace: pipeline?.metadata?.namespace,
196	      prop: 'task',
197	    },
198	    approvalTask: {
199	      groupVersionKind: getGroupVersionKindForModel(ApprovalTaskModel),
200	      name: customTaskName,
201	      namespace: pipeline?.metadata?.namespace,
202	      prop: 'task',
203	    },
204	  };
205	
206	  const resourcesData: WatchK8sResults<WatchResource> =
207	    useK8sWatchResources<WatchResource>(watchedResources);
208	
209	  const approvalStatus = getApprovalStatus(
210	    resourcesData.approvalTask?.data,
211	    pipelineRun,
212	  );
213	
214	  const taskComponent: JSX.Element = (
215	    <ApprovalTaskComponent
216	      pipelineRunName={pipelineRun?.metadata?.name}
217	      name={task.name || ''}
218	      task={task.taskSpec && { data: { spec: task.taskSpec } }}
219	      namespace={pipeline?.metadata?.namespace}
220	      status={approvalStatus}
221	      disableVisualizationTooltip={disableTooltip}
222	      width={width}
223	      height={height}
224	      customTask={resourcesData.approvalTask?.data as ApprovalTaskKind}
225	    />
226	  );
227	  return taskComponent;
228	};
229	
230	export default React.memo(observer(ApprovalTaskNode));

